#!/bin/bash\n\n# دليل إعداد Capacitor للتطبيق المحمول\n# Game Server Mobile Setup\n\necho \"🚀 بدء إعداد تطبيق Capacitor...\"\necho \"\"\n\n# 1. تثبيت الحزم\necho \"📦 تثبيت الحزم المطلوبة...\"\nnpm install @capacitorjs/core @capacitorjs/cli --save\nnpm install @capacitorjs/android @capacitorjs/device @capacitorjs/storage @capacitorjs/camera --save\n\necho \"✅ تم تثبيت الحزم\"\necho \"\"\n\n# 2. تهيئة Capacitor\necho \"⚙️ تهيئة Capacitor...\"\necho \"{\n  \\\"appId\\\": \\\"com.gameserver.ayham\\\",\n  \\\"appName\\\": \\\"Game Server\\\",\n  \\\"webDir\\\": \\\"public\\\"\n}\" > capacitor.config.json\n\necho \"✅ تم إنشاء capacitor.config.json\"\necho \"\"\n\n# 3. إضافة منصة Android\necho \"🤖 إضافة منصة Android...\"\nnpx cap add android\n\necho \"✅ تم إضافة منصة Android\"\necho \"\"\n\n# 4. مزامنة الملفات\necho \"🔄 مزامنة الملفات...\"\nnpx cap sync\n\necho \"✅ تم المزامنة\"\necho \"\"\n\necho \"🎉 تم الإعداد بنجاح!\"\necho \"\"\necho \"الخطوات التالية:\"\necho \"1. npx cap open android - لفتح Android Studio\"\necho \"2. وصّل التلفون بـ USB\"\necho \"3. اضغط الزر الأخضر (Run) في Android Studio\"\necho \"\"\n